/**
 * Simple Budget Test - Debugging React/JSX compilation issues
 */

import React from 'react';
import { render, screen } from '@testing-library/react';
import { QueryClient, QueryClientProvider } from '@tanstack/react-query';
import { describe, it, expect, beforeEach, jest } from '@jest/globals';
import '@testing-library/jest-dom';

// Try importing the mock directly to test
import BudgetMock, { BudgetInner } from '../../__mocks__/client/src/pages/manager/budget';

describe('Simple Budget Test', () => {
  let queryClient: QueryClient;

  beforeEach(() => {
    queryClient = new QueryClient({
      defaultOptions: {
        queries: { retry: false },
        mutations: { retry: false },
      },
    });
    jest.clearAllMocks();
  });

  it('should render BudgetMock component', () => {
    render(
      <QueryClientProvider client={queryClient}>
        <BudgetMock buildingId="test-123" organizationId="org-123" />
      </QueryClientProvider>
    );

    expect(screen.getByTestId('budget-page')).toBeInTheDocument();
    expect(screen.getByTestId('button-budget-settings')).toBeInTheDocument();
  });

  it('should render BudgetInner component', () => {
    render(
      <QueryClientProvider client={queryClient}>
        <BudgetInner buildingId="test-123" organizationId="org-123" />
      </QueryClientProvider>
    );

    expect(screen.getByTestId('budget-page')).toBeInTheDocument();
    expect(screen.getByText('Budget Settings')).toBeInTheDocument();
  });

  it('should render settings inputs', () => {
    render(
      <QueryClientProvider client={queryClient}>
        <BudgetInner buildingId="test-123" organizationId="org-123" />
      </QueryClientProvider>
    );

    expect(screen.getByTestId('input-start-amount')).toBeInTheDocument();
    expect(screen.getByTestId('input-minimum-fund')).toBeInTheDocument();
    expect(screen.getByTestId('input-general-inflation')).toBeInTheDocument();
    expect(screen.getByTestId('input-revenue-inflation')).toBeInTheDocument();
  });
});